528→export const getFollowingFeedService = async(limit, userId, before) => {
529→    if (!userId) {
530→        throw { status: 401, error: 'authentication required' };
531→    }
532→    if (isNaN(limit) || limit > 20 || limit < 1) {
533→        throw { status: 400, error: 'limit should be integer, not below 1 and higher than 20' };
534→    }
535→
536→    const parsedLimit = parseInt(limit);
537→
538→    // Step 1: Fetch journals via RPC (subquery stays inside Postgres — scales to 100k+ followings)
539→    const { data: rpcData, error } = await supabase.rpc('get_following_feed', {
540→        p_user_id: userId,
541→        p_limit: parsedLimit + 1,
542→        p_before: before || null
543→    });
544→
545→    if (error) {
546→        console.error('supabase error fetching following feed:', error.message);
547→        throw { status: 500, error: 'supabase error fetching following feed' };
548→    }
549→
550→    if (!rpcData || rpcData.length === 0) {
551→        return { data: [], hasMore: false };
552→    }
553→
554→    // Reshape RPC rows to match PostgREST format the client expects
555→    const data = rpcData.map(row => ({
556→        id: row.id,
557→        user_id: row.user_id,
558→        title: row.title,
559→        content: row.content,
560→        post_type: row.post_type,
561→
562→        created_at: row.created_at,
563→        privacy: row.privacy,
564→        views: row.views,
565→        is_repost: row.is_repost,
566→        repost_source_journal_id: row.repost_source_journal_id,
567→        repost_caption: row.repost_caption,
568→        prompt_id: row.prompt_id,
569→        users: { id: row.user_obj_id, name: row.user_name, image_url: row.user_image_url, badge: row.user_badge },
570→        like_count: [{ count: Number(row.like_count) }],
571→        reaction_count: [{ count: Number(row.reaction_count) }],
572→        comment_count: [{ count: Number(row.comment_count) }],
573→        bookmark_count: [{ count: Number(row.bookmark_count) }]
574→    }));
575→
576→    // Step 2: Personalization (same pattern as getJournalsService — operates on small result set)
577→    const journalIds = data.map(j => j.id);
578→    const [userLikes, userBookmarks, userReactions] = await Promise.all([
579→        supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
580→        supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
581→        supabase.from('reactions').select('journal_id, reaction_type').in('journal_id', journalIds).eq('user_id', userId)
582→    ]);
583→
584→    const userHasLikedSet = new Set(userLikes.data?.map(j => j.journal_id) || []);
585→    const userHasBookmarkedSet = new Set(userBookmarks.data?.map(j => j.journal_id) || []);
586→    const userReactionMap = new Map((userReactions.data || []).map(r => [r.journal_id, r.reaction_type]));
587→
588→    await attachRepostSources(data);
589→
590→    const formattedData = data.map(journal => ({
591→        ...journal,
592→        has_liked: userHasLikedSet.has(journal.id),
593→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
594→        user_reaction: userReactionMap.get(journal.id) || null
595→    }));
596→
597→    const hasMore = data.length > parsedLimit;
598→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
599→
600→    return { data: slicedData, hasMore };

