 86→export const completeOnboardingService = async(userId, writingInterests, writingGoal) => {
 87→    if(!userId){
 88→        throw {status: 400, error: 'userId is undefined'};
 89→    }
 90→
 91→    const payload = {
 92→        onboarding_completed: true,
 93→        onboarding_completed_at: new Date().toISOString(),
 94→    };
 95→
 96→    if(Array.isArray(writingInterests)){
 97→        payload.writing_interests = writingInterests.filter(i => typeof i === 'string').slice(0, 16);
 98→    }
 99→    if(writingGoal && typeof writingGoal === 'string'){
100→        payload.writing_goal = writingGoal;
101→    }
102→
103→    const {error} = await supabase
104→        .from('users')
105→        .update(payload)
106→        .eq('id', userId);
107→
108→    if(error){
109→        console.error('supabase error completing onboarding:', error.message);
110→        throw {status: 500, error: 'failed to complete onboarding'};
111→    }
112→
113→    return true;
114→}
