 169→export const imageUploader = async(file, userId, bucket) =>{
 170→    if(!file){
 171→        throw new Error('no file received');
 172→    }
 173→
 174→    const sourceBuffer = Buffer.isBuffer(file) ? file : file?.buffer;
 175→    if(!sourceBuffer){
 176→        throw new Error('invalid file payload');
 177→    }
 178→
 179→    let img_buffer = null
 180→    let img_url = null
 181→    img_buffer = await sharp(sourceBuffer)
 182→    .webp({quality: 80})
 183→    .toBuffer();
 184→
 185→    const folderName = `user_id_${userId}`;
 186→    const fileName = `${Date.now()}_${crypto.randomUUID()}.webp`;
 187→    const filePath = `${folderName}/${fileName}`;
 188→
 189→    const {data: uploadImage, error: errorUploadImage} = await supabase.storage
 190→    .from(bucket)
 191→    .upload(filePath, img_buffer, {
 192→        contentType: 'image/webp',
 193→        cacheControl: '31536000',
 194→        upsert: true
 195→    })
 196→    if(errorUploadImage){
 197→        console.error('supabase error while uploading image to supabase bucket', errorUploadImage)
 198→        throw new Error('error uploading image into supabase bucket');
 199→    }
 200→    const {data: data_url} = supabase.storage
 201→    .from(bucket)
 202→    .getPublicUrl(filePath)
 203→    
 204→    if(data_url){
 205→        img_url = data_url.publicUrl;
 206→        return img_url;
 207→    } else {
 208→        throw new Error('Error uploading the image');
 209→    }
 210→}
