 269→router.get('/getFollowsData', async(req, res) => {
 270→    const {userId, loggedInUserId} = req.query;
 271→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
 272→    // console.log(req.query)
 273→    try {
 274→        const followersCountPromise = supabase
 275→        .from('follows')
 276→        .select('*', {count: 'exact', head: true})
 277→        .eq('following_id', userId);
 278→
 279→        const followingCountPromise = supabase
 280→        .from('follows')
 281→        .select('*', {count: 'exact', head: true})
 282→        .eq('follower_id', userId)
 283→
 284→        const isFollowingPromise = supabase
 285→        .from('follows')
 286→        .select('*', {count: 'exact', head: true})
 287→        .eq('follower_id', loggedInUserId)
 288→        .eq('following_id', userId)
 289→
 290→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
 291→            followersCountPromise, followingCountPromise, isFollowingPromise,
 292→        ])
 293→
 294→
 295→        const {count: followersCount, error: errorFollowers } = followersCountResult;
 296→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
 297→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
 298→
 299→        if(errorFollowers || errorFollowings || errorIsfollowing){
 300→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
 301→            return res.status(500).json({error: 'failed to fetch data'})
 302→        }
 303→
 304→        return res.status(200).json({
 305→            followersCount: followersCount,
 306→            followingsCount: followingsCount,
 307→            isFollowing: isFollowingCount > 0
 308→        })
 309→
 310→    } catch (error) {
 311→        console.error('Error in Promise.all:', error);
 312→        res.status(500).json({ error: 'An unexpected error occurred' });
 313→    }
 314→
 315→})
