 413→
 414→        if(hasLiked.error || hasBookMarked.error){
 415→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 416→        }
 417→        hasLikedResult = hasLiked.data || [];
 418→        hasBookMarkedResult = hasBookMarked.data || [];
 419→    }
 420→
 421→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 422→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 423→
 424→    const formatted = merged.map((notif) => ({
 425→        ...notif,
 426→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 427→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 428→    }))
 429→
 430→    const hasMore = formatted.length > parsedLimit;
 431→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
 432→
 433→    return res.status(200).json(
 434→        {
 435→            hasMore: hasMore,
 436→            data: slicedData,
 437→        }
 438→    )
 439→
