 896→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
 897→    if (RESERVED_WORDS.includes(normalized)) {
 898→        return res.status(200).json({ available: false, reason: 'reserved' });
 899→    }
 900→
 901→    const { data: existing, error } = await supabase
 902→        .from('users')
 903→        .select('id')
 904→        .ilike('username', normalized)
 905→        .limit(1);
 906→
 907→    if (error) {
