 915→router.post('/update-username', requireAuth, async (req, res) => {
 916→    const userId = req.userId;
 917→    const { username } = req.body;
 918→
 919→    if (!username || typeof username !== 'string') {
 920→        return res.status(400).json({ error: 'username is required' });
 921→    }
 922→
 923→    const trimmed = username.trim();
 924→    if (trimmed.length < 3 || trimmed.length > 50) {
 925→        return res.status(400).json({ error: 'username must be 3-50 characters' });
 926→    }
 927→
 928→    if (!/^[a-zA-Z0-9-]+$/.test(trimmed)) {
 929→        return res.status(400).json({ error: 'username can only contain letters, numbers, and hyphens' });
 930→    }
 931→
 932→    const normalized = trimmed.toLowerCase();
 933→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
 934→    if (RESERVED_WORDS.includes(normalized)) {
 935→        return res.status(400).json({ error: 'this username is reserved' });
 936→    }
 937→
 938→    // Check uniqueness
 939→    const { data: existing } = await supabase
 940→        .from('users')
 941→        .select('id')
 942→        .ilike('username', normalized)
 943→        .neq('id', userId)
 944→        .limit(1);
 945→
 946→    if (existing && existing.length > 0) {
 947→        return res.status(409).json({ error: 'username is already taken' });
 948→    }
 949→
 950→    const { error: updateError } = await supabase
 951→        .from('users')
 952→        .update({ username: trimmed.toLowerCase() })
 953→        .eq('id', userId);
 954→
 955→    if (updateError) {
 956→        console.error('update-username error:', updateError.message);
 957→        return res.status(500).json({ error: 'failed to update username' });
 958→    }
 959→
 960→    return res.status(200).json({ message: 'success', username: trimmed.toLowerCase() });
 961→});
