The `getUserDataService` selects `*` from `users`, which means `writing_interests` is already available on the client in `user.userData[0].writing_interests`. Now I have all the information I need. Let me create the comprehensive implementation plan.

---

Here is the complete implementation plan for both features.

---

## Implementation Plan: Personalized "For You" Feed + Interest-Based Explore

### Architecture Overview

Both features share a core dependency: an `interests_embedding vector(384)` column on the `users` table. This embedding is a vector representation of the user's selected writing interests, generated at onboarding time and updated whenever interests change. Both the For You feed and the interest-grouped Explore use this embedding (or per-interest embeddings) to perform cosine similarity matching against `journals.embeddings`.

---

## Phase 0: Database Migration & Embedding Infrastructure

### 0A. Migration SQL

**New file: `C:/Users/johnm/iskrib_v3/server/sql/personalized_feed.sql`**

```sql
-- Personalized Feed: interests_embedding + topic_embeddings
-- Run in Supabase SQL editor. Safe to re-run.

-- 1. Add interests_embedding column to users
ALTER TABLE users ADD COLUMN IF NOT EXISTS interests_embedding vector(384);

-- 2. Create a lookup table for the 16 canonical topic embeddings
CREATE TABLE IF NOT EXISTS topic_embeddings (
    topic TEXT PRIMARY KEY,
    embedding vector(384) NOT NULL,
    created_at TIMESTAMPTZ DEFAULT now()
);

-- 3. Index for the For You feed RPC
-- IVFFlat index on journals embeddings already exists (semantic_search.sql)
-- but we add a partial index on users for the interests_embedding
CREATE INDEX IF NOT EXISTS idx_users_interests_embedding
ON users USING ivfflat (interests_embedding vector_cosine_ops)
WITH (lists = 20)
WHERE interests_embedding IS NOT NULL;

-- 4. get_for_you_feed RPC
DROP FUNCTION IF EXISTS public.get_for_you_feed;
CREATE OR REPLACE FUNCTION public.get_for_you_feed(
    p_user_id UUID,
    p_limit INT DEFAULT 10,
    p_before TIMESTAMPTZ DEFAULT NULL
)
RETURNS TABLE (
    id UUID,
    user_id UUID,
    title TEXT,
    content JSONB,
    post_type TEXT,
    canvas_doc JSONB,
    created_at TIMESTAMPTZ,
    privacy TEXT,
    views INT,
    is_repost BOOLEAN,
    repost_source_journal_id UUID,
    repost_caption TEXT,
    prompt_id INTEGER,
    user_name TEXT,
    user_image_url TEXT,
    user_badge TEXT,
    user_obj_id UUID,
    like_count BIGINT,
    reaction_count BIGINT,
    comment_count BIGINT,
    bookmark_count BIGINT,
    relevance_score FLOAT
)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public, extensions
AS $$
DECLARE
    user_embedding vector(384);
    max_hot BIGINT;
BEGIN
    -- Get user's interests embedding
    SELECT u.interests_embedding INTO user_embedding
    FROM public.users u WHERE u.id = p_user_id;

    -- If no embedding, return empty (user has no interests)
    IF user_embedding IS NULL THEN
        RETURN;
    END IF;

    -- Normalize engagement scores
    SELECT COALESCE(MAX(
        COALESCE(j2.views, 0) * 6
        + j2.cached_like_count * 3
        + j2.cached_comment_count * 2
        + j2.cached_bookmark_count * 2
    ), 1)
    INTO max_hot
    FROM public.journals j2
    WHERE j2.privacy = 'public'
      AND j2.embeddings IS NOT NULL;

    RETURN QUERY
    WITH candidates AS (
        SELECT
            j.id,
            j.user_id,
            j.title,
            j.content::JSONB,
            j.post_type,
            j.canvas_doc,
            j.created_at,
            j.privacy,
            j.views,
            j.is_repost,
            j.repost_source_journal_id,
            j.repost_caption,
            j.prompt_id,
            u.name AS user_name,
            u.image_url AS user_image_url,
            u.badge AS user_badge,
            u.id AS user_obj_id,
            (SELECT COUNT(*) FROM public.likes l WHERE l.journal_id = j.id) AS lk_count,
            (SELECT COUNT(*) FROM public.reactions r WHERE r.journal_id = j.id) AS rx_count,
            (SELECT COUNT(*) FROM public.comments c WHERE c.post_id = j.id) AS cm_count,
            (SELECT COUNT(*) FROM public.bookmarks b WHERE b.journal_id = j.id) AS bk_count,
            (1 - (j.embeddings <=> user_embedding))::FLOAT AS sem_sim,
            (
                COALESCE(j.views, 0) * 6
                + j.cached_like_count * 3
                + j.cached_comment_count * 2
                + j.cached_bookmark_count * 2
            )::BIGINT AS h_score
        FROM public.journals j
        LEFT JOIN public.users u ON u.id = j.user_id
        WHERE j.privacy = 'public'
          AND j.embeddings IS NOT NULL
          AND j.user_id != p_user_id  -- exclude own posts
          AND COALESCE(j.is_repost, false) = false
          AND (1 - (j.embeddings <=> user_embedding)) >= 0.30  -- minimum relevance floor
          AND (p_before IS NULL OR j.created_at < p_before)
        ORDER BY j.embeddings <=> user_embedding
        LIMIT p_limit * 4  -- over-fetch for re-ranking
    )
    SELECT
        c.id,
        c.user_id,
        c.title,
        c.content,
        c.post_type,
        c.canvas_doc,
        c.created_at,
        c.privacy,
        c.views,
        c.is_repost,
        c.repost_source_journal_id,
        c.repost_caption,
        c.prompt_id,
        c.user_name,
        c.user_image_url,
        c.user_badge,
        c.user_obj_id,
        c.lk_count AS like_count,
        c.rx_count AS reaction_count,
        c.cm_count AS comment_count,
        c.bk_count AS bookmark_count,
        (
            -- 60% semantic similarity to interests
            0.60 * c.sem_sim
            -- 25% normalized engagement (hot score)
            + 0.25 * (c.h_score::FLOAT / GREATEST(max_hot, 1))
            -- 15% recency (decay over 90 days)
            + 0.15 * GREATEST(0, 1.0 - EXTRACT(EPOCH FROM (now() - c.created_at)) / (90 * 86400.0))
        ) AS relevance_score
    FROM candidates c
    ORDER BY relevance_score DESC
    LIMIT p_limit;
END;
$$;

-- 5. get_interest_posts RPC (for Explore interest sections)
DROP FUNCTION IF EXISTS public.get_interest_posts;
CREATE OR REPLACE FUNCTION public.get_interest_posts(
    p_topic_embedding vector(384),
    p_limit INT DEFAULT 6,
    p_recency_days INT DEFAULT 30
)
RETURNS TABLE (
    id UUID,
    user_id UUID,
    title TEXT,
    content JSONB,
    post_type TEXT,
    created_at TIMESTAMPTZ,
    views INT,
    user_name TEXT,
    user_image_url TEXT,
    user_badge TEXT,
    username TEXT,
    like_count BIGINT,
    comment_count BIGINT,
    bookmark_count BIGINT,
    relevance_score FLOAT
)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public, extensions
AS $$
DECLARE
    max_hot BIGINT;
BEGIN
    SELECT COALESCE(MAX(
        COALESCE(j2.views, 0) * 6
        + j2.cached_like_count * 3
        + j2.cached_comment_count * 2
        + j2.cached_bookmark_count * 2
    ), 1)
    INTO max_hot
    FROM public.journals j2
    WHERE j2.privacy = 'public'
      AND j2.embeddings IS NOT NULL
      AND j2.created_at > now() - (p_recency_days || ' days')::INTERVAL;

    RETURN QUERY
    SELECT
        j.id,
        j.user_id,
        j.title,
        j.content::JSONB,
        j.post_type,
        j.created_at,
        j.views,
        u.name AS user_name,
        u.image_url AS user_image_url,
        u.badge AS user_badge,
        u.username::TEXT,
        (SELECT COUNT(*) FROM public.likes l WHERE l.journal_id = j.id) AS like_count,
        (SELECT COUNT(*) FROM public.comments c WHERE c.post_id = j.id) AS comment_count,
        (SELECT COUNT(*) FROM public.bookmarks b WHERE b.journal_id = j.id) AS bookmark_count,
        (
            0.50 * (1 - (j.embeddings <=> p_topic_embedding))::FLOAT
            + 0.35 * ((
                COALESCE(j.views, 0) * 6
                + j.cached_like_count * 3
                + j.cached_comment_count * 2
                + j.cached_bookmark_count * 2
            )::FLOAT / GREATEST(max_hot, 1))
            + 0.15 * GREATEST(0, 1.0 - EXTRACT(EPOCH FROM (now() - j.created_at)) / (p_recency_days * 86400.0))
        ) AS relevance_score
    FROM public.journals j
    LEFT JOIN public.users u ON u.id = j.user_id
    WHERE j.privacy = 'public'
      AND j.embeddings IS NOT NULL
      AND COALESCE(j.is_repost, false) = false
      AND j.created_at > now() - (p_recency_days || ' days')::INTERVAL
      AND (1 - (j.embeddings <=> p_topic_embedding)) >= 0.35
    ORDER BY relevance_score DESC
    LIMIT p_limit;
END;
$$;
```

**Design rationale for the scoring weights:**

- **For You feed (60% semantic / 25% engagement / 15% recency):** Lower semantic weight than `find_related_posts` (85%) because interests are broad categories, not specific post content. Higher engagement weight rewards quality content. The 90-day recency window prevents stale feeds.
- **Interest sections (50% semantic / 35% engagement / 15% recency):** Even more engagement-weighted since these are "Trending in X" sections. Uses a 30-day window for freshness.

### 0B. Server-Side Embedding Utilities

**Modify: `C:/Users/johnm/iskrib_v3/server/utils/GenerateEmbeddings.js`**

No changes needed. The existing `GenerateEmbeddings(title, body)` function works perfectly for generating interest embeddings. To generate an embedding for interests like `['Poetry', 'Fiction', 'Philosophy']`, we pass it as: `GenerateEmbeddings('Poetry, Fiction, Philosophy', '')`.

**New file: `C:/Users/johnm/iskrib_v3/server/services/interestEmbeddingService.js`**

This service handles:
1. Generating a single combined embedding from a user's interest array
2. Bootstrapping the `topic_embeddings` lookup table at server start
3. Providing cached access to per-topic embeddings

```javascript
// interestEmbeddingService.js

import supabase from './supabase.js';
import GenerateEmbeddings from '../utils/GenerateEmbeddings.js';

const TOPICS = [
    'Poetry', 'Fiction', 'Journals', 'Essays',
    'Philosophy', 'Self-Reflection', 'Creative Nonfiction', 'Short Stories',
    'Science', 'Nature', 'Music', 'Art',
    'Travel', 'Technology', 'Mental Health', 'Spirituality',
];

// In-memory cache for topic embeddings (loaded once at startup)
let topicEmbeddingsCache = null;

/**
 * Generate a combined interests embedding from an array of topic strings.
 * Concatenates topics into a descriptive string and runs through the model.
 */
export async function generateInterestsEmbedding(interests) {
    if (!Array.isArray(interests) || interests.length === 0) {
        return null;
    }

    // Build a descriptive string for richer embedding
    const descriptiveString = interests.join(', ');
    const embedding = await GenerateEmbeddings(descriptiveString, '');
    return embedding;
}

/**
 * Update a user's interests_embedding in the database.
 */
export async function updateUserInterestsEmbedding(userId, interests) {
    const embedding = await generateInterestsEmbedding(interests);
    if (!embedding) return false;

    const { error } = await supabase
        .from('users')
        .update({ interests_embedding: embedding })
        .eq('id', userId);

    if (error) {
        console.error('failed to update interests_embedding:', error.message);
        return false;
    }
    return true;
}

/**
 * Bootstrap topic_embeddings table.
 * Called once at server start. Generates embeddings for any topics
 * not already in the table.
 */
export async function bootstrapTopicEmbeddings() {
    const { data: existing, error } = await supabase
        .from('topic_embeddings')
        .select('topic');

    if (error) {
        console.error('failed to fetch topic_embeddings:', error.message);
        return;
    }

    const existingTopics = new Set((existing || []).map(r => r.topic));
    const missing = TOPICS.filter(t => !existingTopics.has(t));

    if (missing.length === 0) {
        console.log('topic_embeddings: all topics present');
        await loadTopicEmbeddingsCache();
        return;
    }

    console.log(`topic_embeddings: generating ${missing.length} missing embeddings...`);

    for (const topic of missing) {
        const embedding = await GenerateEmbeddings(topic, '');
        if (embedding) {
            const { error: insertError } = await supabase
                .from('topic_embeddings')
                .upsert({ topic, embedding }, { onConflict: 'topic' });

            if (insertError) {
                console.error(`failed to insert embedding for "${topic}":`, insertError.message);
            }
        }
    }

    await loadTopicEmbeddingsCache();
    console.log('topic_embeddings: bootstrap complete');
}

/**
 * Load all topic embeddings into memory for fast access.
 */
async function loadTopicEmbeddingsCache() {
    const { data, error } = await supabase
        .from('topic_embeddings')
        .select('topic, embedding');

    if (error) {
        console.error('failed to load topic_embeddings cache:', error.message);
        return;
    }

    topicEmbeddingsCache = new Map();
    for (const row of (data || [])) {
        topicEmbeddingsCache.set(row.topic, row.embedding);
    }
}

/**
 * Get the cached embedding for a specific topic.
