### 2A. Backend Service

**New file: `C:/Users/johnm/iskrib_v3/server/services/exploreInterestsService.js`**

```javascript
import supabase from './supabase.js';
import { getTopicEmbedding } from './interestEmbeddingService.js';

/**
 * For each of the user's interests, find trending posts matching that topic.
 * Returns: { sections: [{ interest: "Poetry", posts: [...] }, ...] }
 */
export async function getInterestSectionsService(userId) {
    if (!userId) {
        throw { status: 401, error: 'authentication required' };
    }

    // Fetch user's writing_interests
    const { data: userData, error: userError } = await supabase
        .from('users')
        .select('writing_interests')
        .eq('id', userId)
        .maybeSingle();

    if (userError) {
        console.error('error fetching user interests:', userError.message);
        throw { status: 500, error: 'failed to fetch user interests' };
    }

    const interests = userData?.writing_interests;
    if (!Array.isArray(interests) || interests.length === 0) {
        return { sections: [] };
    }

    // For each interest, query using that topic's pre-computed embedding
    const sectionPromises = interests.slice(0, 8).map(async (interest) => {
        const topicEmbedding = getTopicEmbedding(interest);
        if (!topicEmbedding) {
            return { interest, posts: [] };
        }

        const { data, error } = await supabase.rpc('get_interest_posts', {
            p_topic_embedding: topicEmbedding,
            p_limit: 6,
            p_recency_days: 30
        });

        if (error) {
            console.error(`error fetching posts for "${interest}":`, error.message);
            return { interest, posts: [] };
        }

        return {
            interest,
            posts: (data || []).map(row => ({
                id: row.id,
                user_id: row.user_id,
                title: row.title,
                content: row.content,
                post_type: row.post_type,
                created_at: row.created_at,
                views: row.views,
                users: {
                    name: row.user_name,
                    image_url: row.user_image_url,
                    badge: row.user_badge,
                    username: row.username
                },
                like_count: [{ count: Number(row.like_count) }],
                comment_count: [{ count: Number(row.comment_count) }],
                bookmark_count: [{ count: Number(row.bookmark_count) }],
            }))
        };
    });

    const sections = await Promise.all(sectionPromises);

    // Filter out sections with fewer than 2 posts (not worth showing)
    const validSections = sections.filter(s => s.posts.length >= 2);

    return { sections: validSections };
}
```

